static void
radix7_n1_scaled_fwd_scalar(
    const double * __restrict__ in_re, const double * __restrict__ in_im,
    double * __restrict__ out_re, double * __restrict__ out_im,
    size_t is, size_t os, size_t vl, double scale)
{
    const double KP623 = 0.623489801858733483364005678595276549458503723;
    const double KP222 = 0.222520933956314392876407737276167608797550201;
    const double KP900 = 0.900968867902419145998749172576935961842536926;
    const double KP974 = 0.974927912181823619341969333618180826306343079;
    const double KP781 = 0.781831482468029803634124164091190323233604431;
    const double KP433 = 0.433883739117558120401696442058891989290714264;

    double x0_re,x0_im,x1_re,x1_im,x2_re,x2_im,x3_re,x3_im;
    double x4_re,x4_im,x5_re,x5_im,x6_re,x6_im;
    double spill_re[6], spill_im[6];
    double ar,ai,br,bi,cr,ci,dr,di,er,ei,fr,fi;
    double R1r,R1i,R2r,R2i,R3r,R3i;

    for (size_t k = 0; k < vl; k++) {
        x0_re = in_re[0*is+k]; x0_im = in_im[0*is+k];
        x1_re = in_re[1*is+k]; x1_im = in_im[1*is+k];
        x2_re = in_re[2*is+k]; x2_im = in_im[2*is+k];
        x3_re = in_re[3*is+k]; x3_im = in_im[3*is+k];
        x4_re = in_re[4*is+k]; x4_im = in_im[4*is+k];
        x5_re = in_re[5*is+k]; x5_im = in_im[5*is+k];
        x6_re = in_re[6*is+k]; x6_im = in_im[6*is+k];

        /* DFT-7 butterfly [fwd] */
        /* Phase 1 — symmetric/antisymmetric pairs */
        ar=(x1_re)+(x6_re); ai=(x1_im)+(x6_im);
        dr=(x1_re)-(x6_re); di=(x1_im)-(x6_im);
        br=(x2_re)+(x5_re); bi=(x2_im)+(x5_im);
        er=(x2_re)-(x5_re); ei=(x2_im)-(x5_im);
        cr=(x3_re)+(x4_re); ci=(x3_im)+(x4_im);
        fr=(x3_re)-(x4_re); fi=(x3_im)-(x4_im);
        /* Spill diffs d,e,f */
        spill_re[0] = dr; spill_im[0] = di;
        spill_re[1] = er; spill_im[1] = ei;
        spill_re[2] = fr; spill_im[2] = fi;

        /* Phase 2 — R-term first level + y0 + R completion */
        /* 3 independent R seeds from x0 (critical path: 1 FMA latency) */
        { double t1r=(x0_re)-(KP900)*(cr), t1i=(x0_im)-(KP900)*(ci);
          double t2r=(x0_re)-(KP222)*(ar), t2i=(x0_im)-(KP222)*(ai);
          double t3r=(x0_re)-(KP900)*(ar), t3i=(x0_im)-(KP900)*(ai);
          R1r=(KP623)*(ar)+((t1r)-(KP222)*(br));
          R1i=(KP623)*(ai)+((t1i)-(KP222)*(bi));
          R2r=(KP623)*(cr)+((t2r)-(KP900)*(br));
          R2i=(KP623)*(ci)+((t2i)-(KP900)*(bi));
          R3r=((KP623)*(br)+(t3r))-(KP222)*(cr);
          R3i=((KP623)*(bi)+(t3i))-(KP222)*(ci); }
        x0_re=(x0_re)+(((ar)+(br))+(cr));
        x0_im=(x0_im)+(((ai)+(bi))+(ci));
        /* Spill R1, R2, R3  (a,b,c,x0 dead after this) */
        spill_re[3] = R1r; spill_im[3] = R1i;
        spill_re[4] = R2r; spill_im[4] = R2i;
        spill_re[5] = R3r; spill_im[5] = R3i;

        /* Phase 3 — sine S terms + combine */
        dr = spill_re[0]; di = spill_im[0];
        er = spill_re[1]; ei = spill_im[1];
        fr = spill_re[2]; fi = spill_im[2];

        /* Pair k=1 -> y1, y6 */
        R1r = spill_re[3]; R1i = spill_im[3];
        { double S1re=(KP433)*(fi)+((KP974)*(ei)+((KP781)*(di)));
          double S1pos=(KP433)*(fr)+((KP974)*(er)+((KP781)*(dr)));
          x1_re=(R1r)+(S1re); x1_im=(R1i)-(S1pos);
          x6_re=(R1r)-(S1re); x6_im=(R1i)+(S1pos); }

        /* Pair k=2 -> y2, y5 */
        R2r = spill_re[4]; R2i = spill_im[4];
        { double S2re=(KP974)*(di)-((KP433)*(ei)+((KP781)*(fi)));
          double S2pos=(KP974)*(dr)-((KP433)*(er)+((KP781)*(fr)));
          x2_re=(R2r)+(S2re); x2_im=(R2i)-(S2pos);
          x5_re=(R2r)-(S2re); x5_im=(R2i)+(S2pos); }

        /* Pair k=3 -> y3, y4 */
        R3r = spill_re[5]; R3i = spill_im[5];
        { double S3re=(KP974)*(fi)+(((KP433)*(di))-(KP781)*(ei));
          double S3pos=(KP974)*(fr)+(((KP433)*(dr))-(KP781)*(er));
          x3_re=(R3r)+(S3re); x3_im=(R3i)-(S3pos);
          x4_re=(R3r)-(S3re); x4_im=(R3i)+(S3pos); }

        out_re[0*os+k] = scale * x0_re; out_im[0*os+k] = scale * x0_im;
        out_re[1*os+k] = scale * x1_re; out_im[1*os+k] = scale * x1_im;
        out_re[2*os+k] = scale * x2_re; out_im[2*os+k] = scale * x2_im;
        out_re[3*os+k] = scale * x3_re; out_im[3*os+k] = scale * x3_im;
        out_re[4*os+k] = scale * x4_re; out_im[4*os+k] = scale * x4_im;
        out_re[5*os+k] = scale * x5_re; out_im[5*os+k] = scale * x5_im;
        out_re[6*os+k] = scale * x6_re; out_im[6*os+k] = scale * x6_im;
    }
}

